#!/usr/bin/env node
/**
 * Phase 6B.1 — End-to-end smoke test runner (local production sim + smoke overrides).
 * Does NOT deploy. Requires stack up and scripts/create-smoke-data.ts executed first.
 *
 * Usage:
 *   node scripts/run-e2e-smoke.mjs
 *   node scripts/run-e2e-smoke.mjs --skip-restart
 *
 * Reads credentials from scripts/.smoke-credentials.json (generated by create-smoke-data.ts).
 */
import { createHash, createHmac, randomUUID } from 'node:crypto';
import { readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { execSync } from 'node:child_process';
import { mkdirSync } from 'node:fs';

const scriptDir = dirname(fileURLToPath(import.meta.url));
const credPath = join(scriptDir, '.smoke-credentials.json');
const reportPath = join(scriptDir, '..', 'docs', 'PHASE_6B1_E2E_SMOKE_TEST_REPORT.md');

const skipRestart = process.argv.includes('--skip-restart');
const POLL_MS = 2000;
const POLL_MAX = 45;

const results = [];

function loadCredentials() {
  try {
    return JSON.parse(readFileSync(credPath, 'utf8'));
  } catch {
    throw new Error(
      `Missing ${credPath}. Run: docker exec cardon-prod-api node --experimental-strip-types /app/scripts/create-smoke-data.ts`,
    );
  }
}

function buildSignaturePayload(method, path, requestId, rawBody) {
  const bodyHash = createHash('sha256').update(rawBody).digest('hex');
  return `${method.toUpperCase()}:${path}:${requestId}:${bodyHash}`;
}

function signPartnerRequest(secretKey, payload) {
  return createHmac('sha256', secretKey).update(payload).digest('hex');
}

function unwrap(body) {
  if (body && typeof body === 'object' && 'data' in body && body.data != null) {
    return body.data;
  }
  return body;
}

function sepayTransferContent(paymentReference) {
  return `CARDON ${paymentReference}`;
}

async function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function request(baseUrl, path, options = {}) {
  const url = `${baseUrl.replace(/\/$/, '')}${path}`;
  const res = await fetch(url, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...(options.headers ?? {}),
    },
  });
  const text = await res.text();
  let body;
  try {
    body = text ? JSON.parse(text) : null;
  } catch {
    body = text;
  }
  return { status: res.status, ok: res.ok, body };
}

function record(task, pass, detail) {
  results.push({ task, pass, detail });
  const icon = pass ? 'PASS' : 'FAIL';
  console.log(`[${icon}] ${task}: ${detail}`);
}

async function login(baseUrl, email, password) {
  const res = await request(baseUrl, '/api/v1/auth/login', {
    method: 'POST',
    body: JSON.stringify({ identifier: email, password }),
  });
  if (!res.ok) {
    throw new Error(`Login failed for ${email}: ${JSON.stringify(res.body)}`);
  }
  const token = res.body?.accessToken ?? res.body?.data?.accessToken;
  if (!token) {
    throw new Error(`Login failed for ${email}: ${JSON.stringify(res.body)}`);
  }
  return token;
}

async function pollUntil(label, fn, predicate, maxAttempts = POLL_MAX) {
  for (let i = 0; i < maxAttempts; i += 1) {
    const value = await fn();
    if (predicate(value)) {
      return value;
    }
    await sleep(POLL_MS);
  }
  throw new Error(`${label}: timeout after ${maxAttempts * (POLL_MS / 1000)}s`);
}

async function task2CustomerFlow(creds) {
  const { baseUrl, customer, catalog, payment } = creds;
  const guestEmail = `smoke-${Date.now()}@local.test`;

  const home = await request(baseUrl, '/');
  record(
    'T2 — Open localhost',
    home.status === 200,
    `GET / → HTTP ${home.status}`,
  );

  const products = await request(baseUrl, '/api/v1/products');
  const productList = unwrap(products.body) ?? products.body;
  const items = Array.isArray(productList) ? productList : productList?.items ?? [];
  const variant = items
    .flatMap((p) => p.variants ?? [])
    .find((v) => v.sku === catalog.variantSku);

  if (!variant?.id) {
    record('T2 — Catalog variant', false, `SKU ${catalog.variantSku} not found`);
    return null;
  }
  record('T2 — Catalog variant', true, `variantId=${variant.id}`);

  const orderRes = await request(baseUrl, '/api/v1/orders', {
    method: 'POST',
    body: JSON.stringify({
      items: [{ variantId: variant.id, quantity: 1 }],
      guestEmail,
    }),
  });
  if (!orderRes.ok) {
    record('T2 — Create order', false, JSON.stringify(orderRes.body));
    return null;
  }
  const order = unwrap(orderRes.body);
  record('T2 — Create order', true, `orderCode=${order.orderCode}`);

  const idempotencyKey = randomUUID();
  const payRes = await request(baseUrl, '/api/v1/payments', {
    method: 'POST',
    headers: { 'Idempotency-Key': idempotencyKey },
    body: JSON.stringify({ orderId: order.id, gateway: 'SEPAY' }),
  });
  if (!payRes.ok) {
    record('T2 — Create payment', false, JSON.stringify(payRes.body));
    return null;
  }
  const paymentRow = unwrap(payRes.body);
  record('T2 — Create payment', true, `ref=${paymentRow.paymentReference}`);

  const webhookPayload = {
    id: Math.floor(Math.random() * 900000) + 100000,
    content: sepayTransferContent(paymentRow.paymentReference),
    transferType: 'in',
    transferAmount: Number(order.totalAmount ?? variant.sellPrice ?? 100000),
  };
  const webhook = await request(baseUrl, '/api/v1/payments/webhook/sepay', {
    method: 'POST',
    headers: { Authorization: `Apikey ${payment.sepayApiKey}` },
    body: JSON.stringify(webhookPayload),
  });
  record(
    'T2 — Payment webhook',
    webhook.ok,
    webhook.body?.ok === true || webhook.ok
      ? 'SePay webhook accepted'
      : JSON.stringify(webhook.body),
  );

  let fulfilled;
  try {
    fulfilled = await pollUntil(
      'T2 — Fulfillment',
      () => request(baseUrl, `/api/v1/orders/lookup?orderCode=${order.orderCode}&email=${encodeURIComponent(guestEmail)}`),
      (r) => {
        const o = unwrap(r.body);
        return o?.fulfillmentStatus === 'COMPLETED';
      },
    );
  } catch (e) {
    record('T2 — Fulfillment poll', false, e.message);
    return { order, guestEmail };
  }

  const lookup = unwrap(fulfilled.body);
  record(
    'T2 — Provider fulfillment',
    lookup?.fulfillmentStatus === 'COMPLETED',
    `fulfillmentStatus=${lookup?.fulfillmentStatus}, paymentStatus=${lookup?.paymentStatus}`,
  );

  const cards = await request(
    baseUrl,
    `/api/v1/orders/lookup/cards?orderCode=${order.orderCode}&email=${encodeURIComponent(guestEmail)}`,
  );
  const cardList = unwrap(cards.body)?.cards ?? unwrap(cards.body);
  const hasCards = Array.isArray(cardList) ? cardList.length > 0 : !!cardList;
  record(
    'T2 — Card visible',
    hasCards && lookup?.fulfillmentStatus === 'COMPLETED',
    hasCards ? `${Array.isArray(cardList) ? cardList.length : 1} card(s)` : 'no cards',
  );

  return { order, guestEmail, paymentReference: paymentRow.paymentReference };
}

async function task3AgentFlow(creds) {
  const { baseUrl, agent, catalog } = creds;

  const token = await login(baseUrl, agent.email, agent.password);

  const me = await request(baseUrl, '/api/v1/agents/me', {
    headers: { Authorization: `Bearer ${token}` },
  });
  const meData = unwrap(me.body);
  const balance = meData?.balance?.available ?? meData?.balance ?? meData?.availableBalance;
  record(
    'T3 — Partner login + balance',
    me.ok && balance != null,
    `balance=${typeof balance === 'object' ? JSON.stringify(balance) : balance}, status=${meData?.status}`,
  );

  const credStatus = await request(baseUrl, '/api/v1/agents/me/credentials', {
    headers: { Authorization: `Bearer ${token}` },
  });
  const credBody = unwrap(credStatus.body) ?? credStatus.body;
  record(
    'T3 — API credential visible',
    credStatus.ok && credBody?.hasCredentials === true,
    `hasCredentials=${credBody?.hasCredentials}, apiEnabled=${credBody?.apiEnabled}`,
  );

  const requestId = `smoke-${randomUUID()}`;
  const partnerPath = 'api/partner/v1/cards/buy';
  const bodyObj = {
    product_code: catalog.variantSku,
    quantity: 1,
    request_id: requestId,
  };
  const rawBody = JSON.stringify(bodyObj);
  const sigPayload = buildSignaturePayload('POST', partnerPath, requestId, rawBody);
  const signature = signPartnerRequest(agent.secretKey, sigPayload);

  const buy = await request(baseUrl, `/${partnerPath}`, {
    method: 'POST',
    headers: {
      'x-api-key': agent.apiKey,
      'x-signature': signature,
      'x-request-id': requestId,
    },
    body: rawBody,
  });
  record(
    'T3 — POST /api/partner/v1/cards/buy',
    buy.ok,
    `status=${buy.status}, tx=${buy.body?.status ?? buy.body?.data?.status ?? 'n/a'}`,
  );

  let settled;
  try {
    settled = await pollUntil(
      'T3 — Agent order settle',
      async () => {
        const txPath = `api/partner/v1/transactions/${requestId}`;
        const txSig = signPartnerRequest(
          agent.secretKey,
          buildSignaturePayload('GET', txPath, requestId, ''),
        );
        return request(baseUrl, `/${txPath}`, {
          headers: {
            'x-api-key': agent.apiKey,
            'x-signature': txSig,
            'x-request-id': requestId,
          },
        });
      },
      (r) => {
        const st = r.body?.status ?? r.body?.data?.status;
        return st === 'SUCCESS' || st === 'FAILED';
      },
    );
  } catch (e) {
    record('T3 — Transaction settle', false, e.message);
  }

  if (settled) {
    record(
      'T3 — Transaction SUCCESS',
      (settled.body?.status ?? settled.body?.data?.status) === 'SUCCESS',
      JSON.stringify(settled.body?.status ?? settled.body?.data?.status),
    );
  }

  const ledger = await request(baseUrl, '/api/v1/agents/me/ledger', {
    headers: { Authorization: `Bearer ${token}` },
  });
  const entries = ledger.body?.data ?? ledger.body?.entries ?? ledger.body ?? [];
  const types = (Array.isArray(entries) ? entries : entries.items ?? []).map((e) => e.type);
  const hasHold = types.includes('HOLD');
  const hasDebit = types.includes('DEBIT');
  record(
    'T3 — Ledger HOLD',
    hasHold,
    hasHold ? 'HOLD entry found' : `types=${types.join(',')}`,
  );
  record(
    'T3 — Ledger DEBIT',
    hasDebit,
    hasDebit ? 'DEBIT entry found' : `types=${types.join(',')}`,
  );

  return { requestId, agentToken: token };
}

async function task4Finance(creds, adminToken) {
  const { baseUrl, agent } = creds;
  const today = new Date();
  const dateFrom = new Date(today);
  dateFrom.setDate(dateFrom.getDate() - 7);
  const q = `dateFrom=${dateFrom.toISOString()}&dateTo=${today.toISOString()}`;

  const profit = await request(baseUrl, `/api/v1/admin/finance/profit?${q}`, {
    headers: { Authorization: `Bearer ${adminToken}` },
  });
  const p = profit.body?.data ?? profit.body;
  record(
    'T4 — Revenue / cost / profit',
    profit.ok && p?.revenue != null,
    `revenue=${p?.revenue}, providerCost=${p?.providerCost}, grossProfit=${p?.grossProfit}`,
  );

  const statement = await request(
    baseUrl,
    `/api/v1/admin/finance/agents/${agent.agentId}/statement?${q}`,
    { headers: { Authorization: `Bearer ${adminToken}` } },
  );
  record(
    'T4 — Agent ledger statement',
    statement.ok,
    statement.ok ? `entries=${statement.body?.entries?.length ?? statement.body?.data?.entries?.length ?? 'ok'}` : JSON.stringify(statement.body),
  );

  const reports = await request(baseUrl, '/api/v1/admin/finance/reconcile/reports?take=5', {
    headers: { Authorization: `Bearer ${adminToken}` },
  });
  record(
    'T4 — Reconciliation reports',
    reports.ok,
    reports.ok ? `count=${reports.body?.total ?? reports.body?.data?.total ?? 'ok'}` : JSON.stringify(reports.body),
  );
}

async function task5Admin(creds, adminToken, customerCtx) {
  const { baseUrl, agent, catalog } = creds;
  const headers = { Authorization: `Bearer ${adminToken}` };

  const dash = await request(baseUrl, '/api/v1/admin/dashboard', { headers });
  record('T5 — Admin dashboard', dash.ok, dash.ok ? 'metrics OK' : JSON.stringify(dash.body));

  const orders = await request(baseUrl, '/api/v1/admin/orders?take=10', { headers });
  const orderList = orders.body?.data ?? orders.body?.items ?? [];
  const hasCustomerOrder =
    customerCtx?.order?.orderCode &&
    (Array.isArray(orderList)
      ? orderList.some((o) => o.orderCode === customerCtx.order.orderCode)
      : true);
  record(
    'T5 — Admin orders',
    orders.ok && (hasCustomerOrder || orderList.length > 0),
    `listed=${Array.isArray(orderList) ? orderList.length : 'ok'}`,
  );

  const payments = await request(baseUrl, '/api/v1/admin/payments?take=10', { headers });
  record(
    'T5 — Admin payments',
    payments.ok,
    payments.ok ? `listed=${payments.body?.total ?? payments.body?.data?.total ?? 'ok'}` : JSON.stringify(payments.body),
  );

  const agents = await request(baseUrl, '/api/v1/admin/agents?take=10', { headers });
  const agentList = agents.body?.data ?? agents.body?.items ?? [];
  const hasSmokeAgent = Array.isArray(agentList)
    ? agentList.some((a) => a.id === agent.agentId || a.contactEmail === agent.email)
    : agents.ok;
  record(
    'T5 — Admin agents',
    agents.ok && hasSmokeAgent,
    hasSmokeAgent ? `agentId=${agent.agentId}` : JSON.stringify(agents.body),
  );

  const providers = await request(baseUrl, '/api/v1/admin/providers/status', { headers });
  const provList = providers.body?.data ?? providers.body ?? [];
  const hasEsale = Array.isArray(provList)
    ? provList.some((p) => p.code === catalog.providerCode)
    : providers.ok;
  record(
    'T5 — Admin providers',
    providers.ok && hasEsale,
    hasEsale ? `${catalog.providerCode} listed` : JSON.stringify(providers.body),
  );

  const profit = await request(
    baseUrl,
    `/api/v1/admin/finance/profit?dateFrom=${new Date(Date.now() - 86400000 * 7).toISOString()}&dateTo=${new Date().toISOString()}`,
    { headers },
  );
  record(
    'T5 — Admin finance',
    profit.ok,
    profit.ok ? `orderCount=${profit.body?.orderCount ?? profit.body?.data?.orderCount}` : JSON.stringify(profit.body),
  );
}

async function task6Restart(creds, customerCtx) {
  if (skipRestart) {
    record('T6 — Restart recovery', true, 'skipped (--skip-restart)');
    return;
  }

  let beforeCount;
  try {
    const out = execSync(
      'docker exec cardon-prod-postgres psql -U cardon -d cardon -t -c "SELECT COUNT(*) FROM orders;"',
      { encoding: 'utf8' },
    );
    beforeCount = Number(out.trim());
  } catch (e) {
    record('T6 — Pre-restart order count', false, e.message);
    return;
  }
  record('T6 — Pre-restart order count', true, String(beforeCount));

  try {
    execSync(
      'docker compose -f docker-compose.production.yml -f docker-compose.local-production.yml -f docker-compose.smoke.yml --env-file .env.local-production restart api worker',
      { cwd: join(scriptDir, '..'), stdio: 'pipe' },
    );
  } catch (e) {
    record('T6 — Restart api/worker', false, e.message);
    return;
  }
  record('T6 — Restart api/worker', true, 'containers restarted');

  await sleep(15000);

  const ready = await pollUntil(
    'T6 — Health ready',
    () => request(creds.baseUrl, '/health/ready'),
    (r) => r.body?.ready === true || r.body?.status === 'ok',
    30,
  );
  record(
    'T6 — Health /ready',
    ready.ok,
    JSON.stringify(ready.body?.ready ?? ready.body?.status),
  );

  let afterCount;
  try {
    const out = execSync(
      'docker exec cardon-prod-postgres psql -U cardon -d cardon -t -c "SELECT COUNT(*) FROM orders;"',
      { encoding: 'utf8' },
    );
    afterCount = Number(out.trim());
  } catch (e) {
    record('T6 — Post-restart order count', false, e.message);
    return;
  }
  record(
    'T6 — No data lost',
    afterCount >= beforeCount,
    `before=${beforeCount}, after=${afterCount}`,
  );

  if (customerCtx?.order?.orderCode) {
    const lookup = await request(
      creds.baseUrl,
      `/api/v1/orders/lookup?orderCode=${customerCtx.order.orderCode}&email=${encodeURIComponent(customerCtx.guestEmail)}`,
    );
    const o = lookup.body?.data ?? lookup.body;
    record(
      'T6 — Order persisted after restart',
      lookup.ok && o?.orderCode === customerCtx.order.orderCode,
      `orderCode=${o?.orderCode}`,
    );
  }

  const workers = await request(creds.baseUrl, '/health');
  record(
    'T6 — Queues / workers',
    workers.body?.workers === 'ok' || workers.body?.checks?.workers?.status === 'ok',
    JSON.stringify(workers.body?.workers ?? workers.body?.checks?.workers),
  );
}

function writeReport(creds) {
  const passCount = results.filter((r) => r.pass).length;
  const failCount = results.filter((r) => !r.pass).length;
  const verdict = failCount === 0 ? 'PASS' : failCount <= 2 ? 'PASS (có điều kiện)' : 'FAIL';

  const lines = [
    '# CardOn.vn — Phase 6B.1: E2E Smoke Test Report',
    '',
    `**Ngày:** ${new Date().toISOString().slice(0, 10)}`,
    '**Phạm vi:** Smoke test tooling + verify flows trên local production sim (không VPS)',
    `**Verdict:** **${verdict}** — ${passCount} PASS / ${failCount} FAIL`,
    '',
    '---',
    '',
    '## Chuẩn bị',
    '',
    '```bash',
    'docker compose \\',
    '  -f docker-compose.production.yml \\',
    '  -f docker-compose.local-production.yml \\',
    '  -f docker-compose.smoke.yml \\',
    '  --env-file .env.local-production \\',
    '  up -d --force-recreate api worker',
    '',
    'docker exec cardon-prod-api node --experimental-strip-types /app/scripts/create-smoke-data.ts',
    'node scripts/run-e2e-smoke.mjs',
    '```',
    '',
    '## Kết quả chi tiết',
    '',
    '| Task | Kết quả | Chi tiết |',
    '|------|---------|----------|',
    ...results.map((r) => `| ${r.task} | **${r.pass ? 'PASS' : 'FAIL'}** | ${String(r.detail).replace(/\|/g, '\\|')} |`),
    '',
    '## Smoke accounts',
    '',
    `| Role | Email |`,
    '|------|-------|',
    `| Customer | ${creds.customer.email} |`,
    `| Agent | ${creds.agent.email} |`,
    `| Admin | ${creds.admin.email} |`,
    '',
    `SKU smoke: \`${creds.catalog.variantSku}\``,
    '',
    '---',
    '',
    '*Generated by scripts/run-e2e-smoke.mjs — không deploy VPS.*',
    '',
  ];

  mkdirSync(dirname(reportPath), { recursive: true });
  writeFileSync(reportPath, lines.join('\n'), 'utf8');
  console.log(`\nReport written: ${reportPath}`);
}

async function main() {
  console.log('=== Phase 6B.1 E2E Smoke Test ===\n');
  const creds = loadCredentials();
  const baseUrl = process.env.SMOKE_BASE_URL ?? creds.baseUrl ?? 'http://127.0.0.1';
  creds.baseUrl = baseUrl;
  const adminToken = await login(creds.baseUrl, creds.admin.email, creds.admin.password);

  const customerCtx = await task2CustomerFlow(creds);
  await task3AgentFlow(creds);
  await task4Finance(creds, adminToken);
  await task5Admin(creds, adminToken, customerCtx);
  await task6Restart(creds, customerCtx);

  writeReport(creds);

  const failed = results.filter((r) => !r.pass);
  if (failed.length > 0) {
    process.exitCode = 1;
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
